INSERT INTO beliefs_legacy VALUES('ff4c60cd-9ea3-45d3-8d13-37c725238369','WhatsApp self-chat messages sent from PHONE show as fromMe:false with type:unknown in baileys. Root cause: baileys history sync for self-chat returns 0 messages — the encrypted blob (protocolMessage HISTORY_SYNC_NOTIFICATION) is either empty or baileys can''t decrypt it. Messages from DESKTOP/WEB work fine (fromMe:true, proper body). This is a baileys library limitation, not a bug in our code. Workaround: for the owner-self watcher, accept fromMe:true messages and instruct owner to use desktop WhatsApp for sending commands to Fang.','infrastructure',0.949999999999999955,'[]',0,0,1773987642740,1773987642740,NULL,NULL,NULL,5,'["wa-service","baileys","self-chat","limitation"]','[0.006505684361564628,0.0007879337500576954,0.09076996800664651,0.09161043067337471,0.0037602894139009213,0,0.003634586988163597,0.002401321904937738,0,0.0020126576178074182,0.0007221158950409429,0.002491084164558081,0.02650625815507947,0,0,0.18765488741519024,0.04322379428887929,0.0005961850680495138,0.0007602174874928518,0,0.0002887085496394609,0.09554193241443555,0.005898169248550191,0.0035177238273641056,0.03053391706997033,0.09076996800664651,0.00398386077321008,0.002185192503975855,0.0004144747397563768,0.0011819006250865431,0.013042425049867561,0,0.10716216471988252,0.012000306842523501,0.0003453956164636473,0.0018384288974324545,0.004364349788402088,0.0006738676169758464,0.10156589264430828,0.004912691419872623,0.005932987882122873,0,0.0026635314568444145,0.09321002091005098,0.0005875078835381651,0.003228811404451804,0.0918583369275895,0.02191146799594673,0.02514438209028596,0.0007977284613730096,0.002966338823746618,0.04964162934937236,0.00471782410963533,0.0027980909460658147,0.003932023354730838,0.004687322157570819,0.003529307289035226,0.0005748251501160634,0,0.09149904405489268,0.009046541932051939,0.0019395292309112501,0.09143059368355078,0.005981643103318199,0.11234624434840096,0.0030013942951730445,0.001212