INSERT INTO beliefs_legacy VALUES('91408314-4123-48bc-8640-693b046e24ba','WhatsApp self-chat LID bug FIXED on 2026-03-20. Root cause: phone-sent messages to self-chat use @lid (Linked ID) JIDs instead of @s.whatsapp.net, causing them to be stored under a different chat ID and invisible when querying by phone number. Fix: normalize @lid JIDs to @s.whatsapp.net using sock.user.id at parse time in service.mjs. Also migrated 553 existing LID messages in the cache. Commit c33a180 in ccrice.','infrastructure',0.949999999999999955,'[]',0,0,1773988645216,1773988645216,NULL,NULL,NULL,5,'["wa-service","lid-fix","self-chat","fix-applied"]','[0.028916444901838867,0,0.005459956310000745,0.09465704420582072,0.0021390860315589084,0.0018188635717447006,0.002603742358305096,0.0009529418556278118,0.0021661141944125406,0.0016836684614611674,0.008678577613753284,0,0.002678760650398984,0.09112506494440949,0.001986653405790144,0.001659837248532049,0.044070901944840896,0.0037640133439175434,0.0009433236536688352,0,0.000597933497010561,0.0016838517623570478,0.0011085774324137408,0.0009176743700343353,0.010047542738747941,0.007221640333726812,0,0.005328951166339736,0.0008250204082841867,0.00045471589293617515,0.01170753746154656,0,0.09874604531427175,0,0.0003924421401568023,0.09233042294631966,0.000797244662680748,0.004673080253559461,0.002378487180239871,0.0003759284857442636,0,0.0008187337371465364,0.004741382689506194,0.18606764428365416,0,0.0007555975534362313,0,0.11521388328395754,0.03564455343505779,0.0018596593566833602,0.001735715522750657,0.0533271854849723,0.0037245562259024517,0,0.004863820787464378,0.005577674213621636,0.005207146568251971,0.09517336482459789,0.0011462272320051509,0.010530322312529247,0.12574212022116224,0.00274581369426692,0.015603030918303043,0,0.009899834765898473,0.2739802749457411,0,0.09267570731699133,0.0037968777060170622,0.0025889054429537495,0.002968987078389282,0.0006381307068936238,0.006831232821452774,0,0.0007197872428468364,0,0.004906145160627152,0.