INSERT INTO beliefs_legacy VALUES('b1e702de-4dac-4873-ad22-0ea9041a06fa','CRITICAL FEEDBACK: fang-route must NEVER inject messages into a busy agent window via tmux send-keys. On 2026-03-23, relay messages from yeli-moov-stakeholder were injected while the agent was running a testing sub-agent, interrupting it and causing the test to fail. Fix: fang-route should check if the agent is busy (sub-agent running, tool in progress) before injecting. If busy, queue to inbox file instead. Only inject stakeholder messages when the agent is idle at the prompt. Exception: only interrupt if stakeholder/owner explicitly requests higher priority.','rule',0.989999999999999991,'[]',0,0,1774228502243,1774228502243,NULL,NULL,NULL,5,'["feedback","fang-route","interruption"]','[0.010856778182942475,0,0.0032530622477275357,0.0012567263839060943,0.08634131977697923,0.08445201299848953,0.001490294991184896,0,0.001555285690579918,0.0033476030377875186,0.002065451297370842,0.003992566699227079,0.005556859810818446,0.08804848426194847,0,0.0009051662700802738,0.0016432425571791809,0.008698542803519433,0.0005321487901606146,0,0.0007255327577189823,0.006476223784343434,0,0,0.011938493155888057,0.0042015926864920165,0.0014075335499748258,0,0.08445201299848953,0.0018642828476487757,0.0009199565686109972,0,0.09310989930957589,0.0005687004242322528,0.009774538541491845,0.0017611945186132962,0.002343086514892382,0,0.01308260417178227,0.0034753914814193224,0.00795424883411707,0,0.006587569605961498,0.01759416937468532,0,0.012363426023219498,0,0,0.03187261216880224,0,0.0007330903906118884,0.0002994752233988991,0.0023645858278634664,0.08445201299848953,0.005916234041129176,0.08852273605201011,0.09343986752013601,0.010587357015374119,0.09073078017072747,0.001132292760821701,0.030620591760158467,0,0.0027241541645353167,0.009885351491801806,0.01587305430592096,0.01346336439106355,0.002685889469596945,0.0012593402883745541,0.08661757262293085,0.0003466831403878881,0.007733684034086999,0,0.00454937016767503