INSERT INTO beliefs_legacy VALUES('a36f077f-c8a2-4b98-a671-e75f6ccd8c03','WA bridge DM re-routing fix deployed 2026-03-25. Three-layer fix: (1) watchdog crash-loop (a7ed8cb), (2) LID resolution via auth mappings (07da3ee), (3) linked-device DM re-routing via peerJid+pushName+contacts reverse lookup (7de3afa, 4b62eaa). Root cause: on linked devices, Baileys sends all incoming DMs with remoteJid=owner''s phone and empty participant. 82 historical Hicham messages re-routed from owner self-chat to correct JID. Watermark cursor recovery from messages.jsonl also deployed.','infrastructure',0.949999999999999955,'[]',0,0,1774399511557,1774399511557,NULL,NULL,NULL,5,'["wa-bridge","lid","dm-routing","fix"]','[0.03831276422189566,0.0970171652043996,0.0047215234493172544,0.01598164468055735,0.0031519258394400894,0,0.0011440323417226993,0.0029731809783541245,0.0772221830662822,0.002793176329729579,0.0008927420007662681,0.0022546622793075096,0.10198829883189088,0.09266661967953864,0,0.004373905545973313,0.12073804284534623,0.0006807399373303565,0.023320603611030458,0.09266661967953864,0.10336895925036578,0.003487411879640088,0.09266661967953864,0.09266661967953864,0.008141159253093238,0.0006848974107874253,0.09433776900980001,0.0025112905062205596,0.0005131042064204798,0,0.09934969423110156,0,0.05240487286493669,0,0.005720453723145026,0.0028068954345502007,0.0013033279842410497,0.0006628513567921219,0.001227989156679405,0,0.010487427091152392,0,0.019057714395351415,0.0012596158324333386,0.001178654373116939,0.0008882053727660431,0.000425466573367946,0.0959967138210916,0.008834612585803278,0.09487250703192043,0.0031371752156769033,0.0036105131950625543,0.004165017931923931,0.004033688069841368,0.0030129780964544667,0.0027946193508190907,0.042136743119869834,0.01276877961447355,0,0,0.12346182974725455,0.18778483836591656,0.004280535948242688,0.0005535640363174352,0.003265657784836826,0.1060965645606312,0.003321575211821684,0.00437752996255746,0.09643355543886947,0.00078199679054462