INSERT INTO beliefs VALUES('6bb915e1-b5e5-435e-a892-0cd48cef0e97','Cosware agent misdiagnosed ''Soksc not found'' as a WhatsApp re-auth bug. Root cause: there were simply no messages from Soksc yet. Rule: never attribute empty results to a service bug without first verifying (1) chat name is correct via wa chats, (2) there are actually messages via wa messages --chat, (3) contact exists in contacts.json. Only then consider service-level issues.','rule','directive',0.949999999999999955,5,'["cosware","misdiagnosis","wa-debugging"]',NULL,NULL,NULL,NULL,NULL,NULL,1773813023248,1773813023248,NULL,1775151906481,'Contradicted by b1e702de (auto-resolved by curate)',1773813023);
