INSERT INTO beliefs VALUES('76132941-83d3-4131-9415-b7e65d4a261e','CRITICAL: yeli-moov agent repeatedly skips e2e testing after small fixes (label changes, DB inserts, copy button additions). It implements, commits, and reports done without verifying via agent-browser. This MUST be enforced: EVERY change, no matter how small, requires e2e verification before commit. The coordinator must check for e2e evidence in the agent output before accepting completion reports.','rule','directive',0.989999999999999991,5,'["critical","e2e-testing","enforcement"]',NULL,NULL,NULL,NULL,NULL,NULL,1773940868198,1773940868198,NULL,1775151906446,'Contradicted by b1e702de (auto-resolved by curate)',1773940868);
INSERT INTO beliefs VALUES('6c331329-082b-4196-9cb0-ba48ce5f05bf','fang-poll outgoing message filter FIXED on 2026-03-19. Root cause: fang-poll returned ALL messages including fromMe=true (outgoing Fang reports), which the heartbeat then forwarded back to the coordinator as [WA:owner] messages, cluttering the input. Fix: filter out fromMe messages from output but still advance watermark past them. Exit 1 when only outgoing messages are new.','pattern','fact',0.949999999999999955,5,'["fang-poll","fix-applied","outgoing-filter"]',NULL,NULL,NULL,NULL,NULL,NULL,1773945169929,1773945169929,NULL,1775151906418,'Contradicted by 3ad44c3f (auto-resolved by curate)',1773945169);
INSERT INTO beliefs VALUES('c5b305db-83ed-47e9-88cd-34eb55c522fa','Owner can prefix WhatsApp messages with [IGNORE] or start with ''ignore this'' to prevent fang-poll from forwarding them. Used when owner pastes content in the self-chat for personal reference. Fixed in fang-poll 2026-03-19.','project','fact',0.949999999999999955,5,'["fang-poll","ignore-prefix","owner-preference"]',NULL,NULL,NULL,NULL,NULL,NULL,1773947049123,1773947049123,NULL,1775151906377,'Contradicted by aea90151 (auto-resolved by curate)',1773947049);
INSERT INTO beliefs VALUES('f02d6c80-5419-47f5-a614-00369adadc75','WA service message parser needed unwrapping for nested message containers. Self-chat messages from phone use wrapper types (ephemeralMessage, viewOnceMessage, editedMessage, documentWithCaptionMessage) that weren''t being unwrapped, causing them to appear as ''unknown'' with empty body. Fixed in service.mjs by unwrapping before text extraction. Commit b525296 in ccrice.','pattern','fact',0.861119106655092503,5,'["wa-service","fix-applied","message-parser"]',NULL,NULL,NULL,NULL,NULL,NULL,1773986108855,1777077688504,NULL,NULL,NULL,1773986108);
INSERT INTO beliefs VALUES('ff4c60cd-9ea3-45d3-8d13-37c725238369','WhatsApp self-chat messages sent from PHONE show as fromMe:false with type:unknown in baileys. Root cause: baileys history sync for self-chat returns 0 messages — the encrypted blob (protocolMessage HISTORY_SYNC_NOTIFICATION) is either empty or baileys can''t decrypt it. Messages from DESKTOP/WEB work fine (fromMe:true, proper body). This is a baileys library limitation, not a bug in our code. Workaround: for the owner-self watcher, accept fromMe:true messages and instruct owner to use desktop...','pattern','fact',0.949999999999999955,5,'["wa-service","baileys","self-chat","limitation"]',NULL,NULL,NULL,NULL,NULL,NULL,1773987642740,1773987642740,NULL,1775151906421,'Contradicted by 3ad44c3f (auto-resolved by curate)',1773987642);
INSERT INTO beliefs VALUES('91408314-4123-48bc-8640-693b046e24ba','WhatsApp self-chat LID bug FIXED on 2026-03-20. Root cause: phone-sent messages to self-chat use @lid (Linked ID) JIDs instead of @s.whatsapp.net, causing them to be stored under a different chat ID and invisible when querying by phone number. Fix: normalize @lid JIDs to @s.whatsapp.net using sock.user.id at parse time in service.mjs. Also migrated 553 existing LID messages in the cache. Commit c33a180 in ccrice.','pattern','fact',0.949999999999999955,5,'["wa-service","lid-fix","self-chat","fix-applied"]',NULL,NULL,NULL,NULL,NULL,NULL,1773988645216,1773988645216,NULL,1775151906382,'Contradicted by aea90151 (auto-resolved by curate)',1773988645);
