INSERT INTO beliefs VALUES('5b22ae21-b628-4afd-bbd4-f8e0c337d928','STATE: Yeli-moov 48% building CRM tab (Bakary). Forge-FK at 47%. ATD done. Monqualiopi rotated post-KELVAL. Cosware/JMMJ standby. Fixed statusline.js: was treating 200K as 1M (15/20% thresholds). Now 40/50 for 200K. NEXT: Monitor yeli-moov CRM, check forge FK result, owner notified re v0.42.2 prod deploy. BLOCKERS: none.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1776934840569,NULL,NULL,1776762040569,1776762040569,NULL,1776778086980,'Superseded by new handoff',1776762040000);
INSERT INTO beliefs VALUES('e5235ee2-faf2-4910-9996-a5c82758b232','STATE: All 5 agents idle (cosware 42%, yeli-moov 23%, JMMJ 28%, ATD 31%, monqualiopi fresh). Yeli-moov: Hicham deploy rule fixed (6f0aa1c), CRM Kit de prospection built, owner talking to Bakary re v0.42.2 prod deploy. Forge FK fix committed (0d9bd5e memr). Statusline.js 200K threshold fix live. NEXT: Await owner instructions. No queued tasks. BLOCKERS: none.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1776950886986,NULL,NULL,1776778086986,1776778086986,NULL,1776779331615,'Contradicted by 59dc19fc (auto-resolved by curate)',1776778086000);
INSERT INTO beliefs VALUES('0b265a5f-62f9-4420-ab54-07db715c8a9e','STATE: 5 agents idle. Yeli-moov 23% (CRM Kit built, Hicham rule fixed). Cosware 42%, JMMJ 28%, ATD 31%, Monqualiopi fresh. Forge FK fix done (memr 0d9bd5e). Statusline.js threshold fix live. Owner talking to Bakary re prod deploy. NEXT: Await owner instructions. No queued tasks. BLOCKERS: none.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1776952146003,NULL,NULL,1776779346003,1776779346003,NULL,1776791456392,'Superseded by new handoff',1776779346000);
INSERT INTO beliefs VALUES('97ecdde0-cf68-4d7b-a88c-5e8fbd2a219a','FEEDBACK: Always forward stakeholder messages to project agent even when owner is active in the same chat. Owner presence does not replace agent awareness. Coordinator skipped forwarding Bakary messages on 2026-04-21 assuming owner was handling — agent missed feedback.','rule','directive',0.949999999999999955,3,'["feedback","stakeholder","routing"]',NULL,NULL,NULL,NULL,NULL,NULL,1776787493971,1776787493971,'924368af-ec29-4a86-b908-19bb0dc042ef',NULL,NULL,1776787494000);
INSERT INTO beliefs VALUES('e532c777-177e-4cb2-9eb3-60f11417fcd6','STATE: 5 agents idle. Yeli-moov Kit de prospection built+feedback forwarded. Hicham deploy rule fixed. Forge FK fix done. Statusline threshold fix live. Owner active with Bakary on prod deploy. NEXT: Await owner. BLOCKERS: none.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1776964256398,NULL,NULL,1776791456398,1776791456398,NULL,1776794483661,'Superseded by new handoff',1776791456000);
INSERT INTO beliefs VALUES('213f3e60-8af2-4d6e-9194-181f196340d2','STATE: 5 agents idle. Bakary testing Kit de prospection on dev. All stakeholder msgs now forwarded to agents. Owner handling prod deploy. NEXT: Await Bakary feedback + owner instructions. BLOCKERS: none.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1776967283666,NULL,NULL,1776794483666,1776794483666,NULL,1776804317450,'Superseded by new handoff',1776794483000);
INSERT INTO beliefs VALUES('3dd13cb0-93e2-482b-8243-f152eb7ffd49','STATE: 5 agents idle. Bakary approved Kit de prospection (''Impeccable''), requested 2 new features: multi-doc attach + bulk send to all ambassadors. Injected to yeli-moov. Owner aware of rotation loop bug. NEXT: Await yeli-moov progress on 2 features. Fix heartbeat idle-spam issue. BLOCKERS: coordinator rotation loop.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1776977117456,NULL,NULL,1776804317456,1776804317456,NULL,1777077688481,'Expired (past expires_at)',1776804317000);
INSERT INTO beliefs VALUES('32734437-f299-4e34-a896-a66ab9eb619c','FIX 2026-04-23: Whisper OOM — changed default model from medium (3GB) to small (1GB) in service.mjs and transcribe-batch.py. Medium was OOM-killed with 6 claude agents running (~3GB). Small works for French transcription.','infra','fact',0.949999999999999955,3,'["fix","whisper","oom"]',NULL,NULL,NULL,NULL,NULL,NULL,1776962910126,1776962910126,NULL,NULL,NULL,1776962910000);
INSERT INTO beliefs VALUES('1d465f85-ee8a-4d99-a4df-8f49fb73fc28','HANDOFF 2026-04-23: Yeli-moov v0.43.2 E2E PASS (HEIC fix: 201 Created, validation 422 not 500, HEIC upload 201). Whisper OOM fixed (medium→small). Cosware working on 4-item task list (stats bug, multigroup, dashboard, supervisor). Bakary new feature requests pending (leads search by date, dashboard appointments, Kit copy from ambassador view). Said mail 365 info shared. NEXT: Prod deploy v0.43.2 on owner approval.','handoff','handoff',1.0,3,'["handoff"]',NULL,NULL,NULL,NULL,NULL,NULL,1776970758584,1776970758584,NULL,1776975384539,'Contradicted by newer belief',1776970758000);
INSERT INTO beliefs VALUES('0a0f1b23-be14-42ad-864c-230edfd683d1','Yeli-moov v0.43.2 deployed to prod by owner 2026-04-23 20:11. Bakary confirmed ''Yes magnifique''. HEIC fix + Kit de prospection live.','project','fact',0.989999999999999991,3,'["yeli-moov","deploy","prod"]',NULL,NULL,NULL,NULL,NULL,NULL,1776975384512,1776975384512,'1d465f85-ee8a-4d99-a4df-8f49fb73fc28',1777077698158,'Contradicted by newer belief',1776975384000);
INSERT INTO beliefs VALUES('5d83f6ad-9401-4a10-b57a-79982fb695dd','INCIDENT: yeli-moov agent was force-cleared during malware forensics despite no-clear rule. Likely heartbeat emergency rotation at 60%. Agent recovered from handoff. Must fix: heartbeat should respect active security investigations.','rule','directive',1.0,3,'["rule","yeli-moov","security"]',NULL,NULL,NULL,NULL,NULL,NULL,1777031970916,1777032134547,NULL,NULL,NULL,1777031970000);
INSERT INTO beliefs VALUES('a3bfaaca-036f-4a9e-8f48-06e4178ce6a5','HANDOFF 2026-04-24 night: Cosware v0.64.0 staging GREEN (4 owner tasks done: stats bug, multigroup, clickable stats, supervisor). Awaiting prod approval. Yeli-moov forensics 4/9 done, no-rotate lock active. Whisper fixed (small model). VPS compromise forensics report sent to owner.','handoff','handoff',1.0,3,'["handoff"]',NULL,NULL,NULL,NULL,NULL,NULL,1777067823191,1777067823191,NULL,1777077689302,'Contradicted by 31e13648 (auto-resolved by curate)',1777067823000);
INSERT INTO beliefs VALUES('9e4322b5-9a1a-4464-a542-ec0dbd5be676','STATE: Cosware v0.64.0 staging GREEN (stats bug+multigroup+clickable stats+supervisor). Awaiting prod approval. Yeli-moov forensics 4/9 done, no-rotate lock at fang:2. Whisper OOM fixed (small model). VPS compromise report sent. Statusline threshold fix live. NEXT: Await owner prod approvals. Monitor yeli-moov forensics. BLOCKERS: none.','handoff','handoff',1.0,5,'["handoff"]',NULL,NULL,NULL,1777250498147,NULL,NULL,1777077698147,1777077698147,'0a0f1b23-be14-42ad-864c-230edfd683d1',NULL,NULL,1777077698000);
