/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "beliefs_legacy" (
      id TEXT PRIMARY KEY,
      text TEXT NOT NULL,
      domain TEXT NOT NULL,
      confidence REAL NOT NULL,
      evidence_ids TEXT NOT NULL,
      supporting_count INTEGER DEFAULT 0,
      contradicting_count INTEGER DEFAULT 0,
      derived_at INTEGER NOT NULL,
      last_evaluated INTEGER NOT NULL,
      supersedes_id TEXT,
      invalidated_at INTEGER,
      invalidation_reason TEXT,
      importance INTEGER DEFAULT 5,
      tags TEXT,
      embedding TEXT,
      created_at INTEGER DEFAULT (strftime('%s', 'now')),
      FOREIGN KEY (supersedes_id) REFERENCES "beliefs_legacy"(id)
    );
CREATE TABLE IF NOT EXISTS "beliefs" (
        id TEXT PRIMARY KEY,
        text TEXT NOT NULL CHECK(length(text) <= 500),
        domain TEXT NOT NULL CHECK(domain IN (
          'handoff','watch','project','stakeholder','rule','pattern','infra','skill'
        )),
        belief_type TEXT NOT NULL DEFAULT 'fact' CHECK(belief_type IN (
          'directive','fact','handoff','watch','decision','pending'
        )),
        confidence REAL NOT NULL CHECK(confidence >= 0.0 AND confidence <= 1.0),
        importance INTEGER NOT NULL DEFAULT 3 CHECK(importance >= 1 AND importance <= 5),
        tags TEXT,

        project TEXT,
        stakeholder TEXT,
        verify_by INTEGER,
        expires_at INTEGER,
        action TEXT,
        source_session INTEGER,

        derived_at INTEGER NOT NULL,
        last_evaluated INTEGER NOT NULL,
        supersedes_id TEXT REFERENCES "beliefs"(id),
        invalidated_at INTEGER,
        invalidation_reason TEXT,
        created_at INTEGER DEFAULT (strftime('%s','now') * 1000)
      );
PRAGMA writable_schema=ON;
        text, tags, project, stakeholder,
        content=''beliefs'',
        content_rowid=''rowid'',
        tokenize="unicode61 tokenchars ''-_.''"
      )');
CREATE TABLE IF NOT EXISTS 'beliefs_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'beliefs_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'beliefs_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'beliefs_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE INDEX idx_beliefs_domain ON "beliefs_legacy"(domain);
CREATE INDEX idx_beliefs_active ON "beliefs_legacy"(invalidated_at) WHERE invalidated_at IS NULL;
CREATE INDEX idx_beliefs_confidence ON "beliefs_legacy"(confidence DESC);
CREATE INDEX idx_active ON beliefs(invalidated_at) WHERE invalidated_at IS NULL;
CREATE INDEX idx_domain ON beliefs(domain) WHERE invalidated_at IS NULL;
CREATE INDEX idx_type ON beliefs(belief_type) WHERE invalidated_at IS NULL;
CREATE INDEX idx_importance ON beliefs(importance DESC) WHERE invalidated_at IS NULL;
CREATE INDEX idx_project ON beliefs(project) WHERE invalidated_at IS NULL AND project IS NOT NULL;
CREATE INDEX idx_expires ON beliefs(expires_at) WHERE invalidated_at IS NULL AND expires_at IS NOT NULL;
CREATE INDEX idx_context ON beliefs(invalidated_at, belief_type, importance DESC) WHERE invalidated_at IS NULL;
CREATE TRIGGER beliefs_ai AFTER INSERT ON beliefs BEGIN
      VALUES (NEW.rowid, NEW.text, NEW.tags, NEW.project, NEW.stakeholder);
    END;
CREATE TRIGGER beliefs_ad AFTER DELETE ON beliefs BEGIN
      VALUES('delete', OLD.rowid, OLD.text, OLD.tags, OLD.project, OLD.stakeholder);
    END;
CREATE TRIGGER beliefs_au AFTER UPDATE ON beliefs BEGIN
      VALUES('delete', OLD.rowid, OLD.text, OLD.tags, OLD.project, OLD.stakeholder);
      VALUES (NEW.rowid, NEW.text, NEW.tags, NEW.project, NEW.stakeholder);
    END;
PRAGMA writable_schema=OFF;
COMMIT;
